INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-01272', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '能選擇的人，就是自由的人。但沒有一個選擇，是最好的選擇，因為選擇有其代價。所以我們也可 以反過來說，每一個選擇，都是最好的選擇。成熟的人，在面臨抉擇時，會謹慎考慮，但不會一直 猶豫。因為猶豫不決，便會計較得失。一直停留在原地，對實質沒有幫助，反而讓心靈不自由。 下列選項的敘述，何者合乎上文之意？ 只要願意付出代價，就能找到最好的選擇  面對抉擇時，謹慎考慮常會造成患得患失 選擇之後必須下定決心，才能繼續向前行  不斷停留在選擇中，就能得到最大的自由', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01273', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「臉書是需要被看見、被知道、被安慰、被讚賞、被愛慕的人，展露容顏、曝曬心情的窗口；或 是傾洩怨憤，攻擊敵人的砲台。人們只是寂寞，無邊的寂寞；只是孤獨、無解的孤獨。當人們都 已如蜂群擁入虛擬的網路世界中，找尋消除孤獨與寂寞的友伴，而遺忘了實境世界中，彼此的體 溫、汗味以及可以撫觸的心情；孤獨、寂寞就已在網路世界中，以幾何級數在滋長，成為一種飲 盡百萬瓶礦泉水，也難以止渴的病症。」下列敘述最切合上文意旨的是： 網路互動可免除實境世界的困擾  虛擬世界是消除孤獨之感的場域 使用臉書是內心寂寞的反映之一  臉書是發抒各種情緒的最佳管道 60210', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01274', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「在歷史建築的保存過程中，什麼樣的建築應該被保存？什麼樣的建築可以拆除？經常引起不同 人士的爭辯。官方的重要建築，因為有政治代表性，或因為建築較為華麗精緻，比較容易被保存 下來；但是一般公共建築，則常常面臨拆除的命運。官方建築固然值得保存，但是我認為攸關人 民生活的公共建築，例如火車站、戲院或菜市場等更值得保存，因為這些公共建築是都市居民集 體記憶的儲存所，失去了這些建築，等於失去了許多市民的珍貴記憶，城市居民將有如患了失憶 症的遊魂一樣，不再對這座城市產生認同感。」由本文可知作者認為判斷一座歷史建築是否值得 保存的原則應該是： 建築存在的時間長短   投入建築經費的多寡 建築精巧華麗的程度   建築與人民生活密切相關', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01275', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「有時候覺得許多美學的理論和知識，不管怎麼分析、怎麼討論，也許真的不如把一個人帶到盛 放在春天的花樹底下，讓他在花裡感覺到生命從誕生、綻放、燦爛到凋謝的過程。我相信一個孩 子站在花的前面，他會懂得許許多多的生命，如同古老的基督教《聖經》所說的：『所羅門王最 富有的時候，所有的財富加起來也不如野地裡的一朵百合花。』同樣地，我們在那古老的印度， 釋迦牟尼說法的時候，也曾經拿過一朵落花給大家看，許多人不瞭解那是什麼意思，但其中一位 學生叫迦舍的，微笑了。在這個『拈花微笑』故事的最後，釋迦牟尼將這朵花給了迦舍，並說， 他一生講過的所有的道理，其實不如這朵花。」下列敘述，何者最能呼應文意？ 美學與美感是一種生命智慧  美學與美感是一種知性的理解 美學與美感必須通過教育而來  美學與美感需要有具體的物質對象', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01276', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '地震預警的基本原理，是在地震儀偵測到地震後，在強烈地震波到達之前提早警告民眾。地震波 可分為壓縮波（P 波）和剪力波（S 波），P 波傳播速度較快（約每秒 6.5 公里），會使建築物 上下振動，但破壞力較小；S波傳播速度較慢（約每秒3.5公里），會使建築物左右搖晃，破壞 力較強。國震中心這套地震預警系統即是利用P波傳播速度較快的特性，計算即將傳到的S波強 度與時間，如果震度超過某一標準，可能造成建築物毀損，就立即發出警報。裝置在學校的預警 系統中包括了地震儀，以偵測當地的P波，屬於「現地型預警系統」。除了國震中心，臺灣大學 地質系教授吳逸民也研發了一套現地型預警系統。其預警儀中的地震儀若偵測到地表垂直位移量 超過0.35公分，預警儀會立即發出警報。根據他的研究統計，若 P 波造成的地表垂直位移量超 過0.35公分，則隨後而來的S波震度有一半以上的機率超過五級，九成以上的機率超過四級。 根據上文，下列選項敘述正確的是： 地震發生得以預警，是利用兩種震波傳播的時間差 波的破壞力強，每秒可以摧毀3.5平方里的建築物 由吳逸民研究可知四級以上的地震九成是由P波引起 裝置在學校的預警系統因為技術瑕疵，無法偵測S波 60210', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01277', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '梆子突然敲響，三弦琴開始嗚咽；她微微吃了一驚，下意識地站起身來，向臺前移步，同時張口 唱起來： 雪梅自嘆命薄──思念夫君──淚雙垂 她在臺前唱著，無聊地，眼睛打量著觀眾：三十排的木板椅子只坐了一半，多半是老人和小孩； 老太婆搖著紙扇，斜睨著眼睛；男人噴著紙煙，大口地吞汽水；孩子們在後頭奔跑，打架。賣冰 棒的小孩低聲吆喝著，一只眼搜索顧客，另一眼盯著臺上的她。後臺傳來拆卸重物，搬移箱櫃的 聲響，遲重的，不耐煩的拖拉聲。 從文中，「微微吃了一驚」、「下意識地站起身來」、「無聊地，眼睛打量著觀眾」等語，可知 這位歌仔戲表演者是： 無心於表演  練習不夠熟練  技巧不夠專業  劇團默契不佳', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01278', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「雨映寒空半有無，重樓閒上倚城隅。淺深山色高低樹，一片江南水墨圖。」（劉敞〈登城〉其 一）根據此詩內容，下列那一個選項的景色最接近詩意？ 煙雨霏霏  雨過天青  雨過潮平  驟雨初歇', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01279', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《大學》：「欲治其國者，先齊其家；欲齊其家者，先修其身；欲修其身者，先正其心。」旨在 表達什麼？ 治國的目標    修身的理由 修身、齊家、治國為漸進關係  修身、齊家、治國為因果關係', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01280', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '蘇軾〈留侯論〉：「子房以蓋世之材，不為伊尹、太公之謀，而特出於荊軻、聶政之計，以僥倖 於不死，此圯上老人之所為深惜者也。是故倨傲鮮腆，而深折之，彼其能有所忍也，然後可以就 大事，故曰：孺子可教也。」圯上老人之所以深惜子房者，是因為： 鋒芒太露，傲慢不恭  有勇無謀，成事不足  武術不精，功虧一簣  好高騖遠，虎頭蛇尾', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01281', 'real-estate', 'real-estate-moex-106-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「一老農當稻熟時，擇日食新。其鄰家一人善謔，輒嘲之曰：『爾舊歲食新，曾卜日耶？』曰： 『然。』『今歲舊穀足用耶？』曰：『不足，稱貸而益之耳。』『夫舊歲卜日，而穀猶不足也， 今亦安庸再卜？稻可食，則食之矣。』老農乃始憬然有悟。」（江盈科《雪濤閣集》）根據上文， 下列那一個選項最合乎旨意？ 揭示老農的修為  憐憫老農的貧困  哀傷老農的辛勞  點出老農的愚昧', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "3032f9176e75", "answer_pdf_sha1": "940e9cd5d162", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1301", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
